import{_ as l,n as a,v as c,ac as t}from"./chunks/framework.DFVDdn94.js";const n=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"devops/04-linux.md","filePath":"devops/04-linux.md","lastUpdated":1751535949000}'),i={name:"devops/04-linux.md"};function d(o,e,s,r,m,p){return c(),a("div",null,e[0]||(e[0]=[t('<h2 id="systemctl-服务管理" tabindex="-1">systemctl 服务管理 <a class="header-anchor" href="#systemctl-服务管理" aria-label="Permalink to &quot;systemctl 服务管理&quot;">​</a></h2><p>用来管理服务的命令</p><ul><li><code>systemctl start [ serviceName ]</code> 启动服务</li><li><code>systemctl stop [ serviceName ]</code> 停止服务</li><li><code>systemctl restart [ serviceName ]</code> 重启服务</li><li><code>systemctl reload [ serviceName ]</code> 重载服务，重新加载配置，不重启服务</li><li><code>systemctl status [ serviceName ]</code> 查看服务状态</li><li><code>systemctl enable [ serviceName ]</code> 设置开机自启</li><li><code>systemctl disable [ serviceName ]</code> 取消开机自启</li><li><code>systemctl is-enabled [ serviceName ]</code> 查看是否开机自启</li><li><code>systemctl list-units --type=service --status=running</code> 列出所有运行中的服务</li><li><code>systemctl --failed</code> 列出失败的服务</li></ul><h2 id="yum-包管理" tabindex="-1">yum 包管理 <a class="header-anchor" href="#yum-包管理" aria-label="Permalink to &quot;yum 包管理&quot;">​</a></h2><p>常在 <code>CentOS</code> 中使用的包管理工具。</p><ul><li><code>yum check-update</code> 检查可更新的包</li><li><code>yum update</code> 更新所有包</li><li><code>yum install [ packageName ]</code> 安装包</li><li><code>yum update [ packageName ]</code> 更新包</li><li><code>yum remove [ packageName ]</code> 删除包</li><li><code>yum list [ keyword ]</code> 列出所有可以被安装的包</li><li><code>yum search [ keyword ]</code> 搜索包</li><li><code>yum clean all</code> 清除缓存</li></ul><h2 id="apt-包管理" tabindex="-1">apt 包管理 <a class="header-anchor" href="#apt-包管理" aria-label="Permalink to &quot;apt 包管理&quot;">​</a></h2><p>常在 <code>Ubuntu</code> 中使用的包管理工具。</p><ul><li><code>apt update</code> 列出可更新的包清单</li><li><code>apt upgrade</code> 升级软件包</li><li><code>apt list --upgradable</code> 列出可升级的包</li><li><code>apt list --installed</code> 列出已安装的包</li><li><code>apt full-upgrade</code> 升级软件</li><li><code>apt install [ packageName ]</code> 安装包</li><li><code>apt update [ packageName ]</code> 更新包</li><li><code>apt remove [ packageName ]</code> 删除包</li><li><code>apt search [ keyword ]</code> 搜索包</li></ul>',9)]))}const y=l(i,[["render",d]]);export{n as __pageData,y as default};
